import pickle
from google.cloud import pubsub_v1
from google.oauth2 import service_account

# Load credentials from environment variable
credentials = service_account.Credentials.from_service_account_file(
    'path/to/credentials.json'
)

# Create a Pub/Sub client instance
pubsub_client = pubsub_v1.PublisherClient(credentials=credentials)
subscriber_client = pubsub_v1.SubscriberClient(credentials=credentials)

def process_batch_job(message):
    try:
        # Deserialize message data using pickle.loads()
        data = pickle.loads(message.data)
        
        # Process batch job logic here
        print(f"Processing batch job: {data}")
        
        # Acknowledge the message to indicate it has been processed
        subscriber_client.acknowledge(
            request={"subscription": "your-subscription-name", "message_ids": [message.message_id]}
        )
    except Exception as e:
        # Handle any exceptions that occur during processing
        print(f"Error processing batch job: {e}")

def pull_messages(subscription_name):
    try:
        response = subscriber_client.pull(
            request={"subscription": subscription_name}
        )
        
        for message in response.received_messages:
            process_batch_job(message)
            
        if response.message_ids:
            subscriber_client.acknowledge(
                request={"subscription": subscription_name, "message_ids": response.message_ids}
            )
    except Exception as e:
        print(f"Error pulling messages: {e}")

# Pull messages from the specified subscription
pull_messages("your-subscription-name")